// Example behavioral shift
// Before: approval -> background proposal session (implicit)
// After: approval -> foreground current chat by default

approval.executionMode = userChoice ?? 'foreground_current_chat';
const task = createExecutionTask({ proposalId, originSessionId, executionMode });
linkProposalToTask(proposalId, task.id);

// Executor guard
if (isDetachedShellCommand(cmd)) {
  throw new Error('Detached shell commands are not allowed for validation steps');
}
const result = await runCommandAndCapture(cmd);
assertStepCanComplete(result.exitCode !== null);
